ee:message.ee:set-payload:
%dw 2.0
output application/java
ns ns0 http://www.example.org/Empleados/
---
{
    body: {
        ns0#nuevoEmpleadoResponse: {
            out: "Empleado insertado correctamente",
            error: ""
        }
    } write "application/xml"
}

set-variable.value:
#[{
  mensaje: "WSKey inválida o no proporcionada",
  detalle: "La WSKey recibida no existe en la tabla soapkey",
  codigo: "APP:WSKEY_INVALIDA"
}]

#[{
  mensaje: "Empleado ya existente",
  detalle: "Ya existe un empleado con nifnie " ++ ((vars.empleadoEntrada.nifnie default "desconocido") as String),
  codigo: "APP:EMPLEADO_YA_EXISTE"
}]

#[{
  mensaje: "Nivel no válido o inexistente",
  detalle: "No existe ningún nivel con id " ++ (((vars.empleadoEntrada.idNivel default 0) as Number) as String),
  codigo: "APP:NIVEL_NO_EXISTE"
}]

#[{
  mensaje: "El proceso se ha tenido que cancelar por errores durante la ejecución",
  detalle: (error.errorType.namespace default "APP") ++ ":" ++ (error.errorType.identifier default "UNKNOWN"),
  codigo: (error.errorType.namespace default "APP") ++ ":" ++ (error.errorType.identifier default "UNKNOWN")
}]

ee:message.ee:set-payload:
%dw 2.0
output application/java
ns ns0 http://www.example.org/Empleados/
---
{
    body: {
        ns0#borrarEmpleadoResponse: {
            out: "Empleado borrado correctamente",
            error: ""
        }
    } write "application/xml"
}

file:write.file:content:
#[%dw 2.0
output application/json
---
{
  operacion: vars.operacion,
  correcto: true,
  fechaHora: now() as String {format: "yyyy-MM-dd HH:mm:ss"},
  mensaje: "Empleado borrado correctamente",
  empleadoBorrado: {
    nifnie: vars.nifnie
  }
}]

set-variable.value:
#[{
  mensaje: "WSKey inválida o no proporcionada",
  detalle: "La WSKey recibida no existe en la tabla soapkey",
  codigo: "APP:WSKEY_INVALIDA"
}]

#[{
  mensaje: "Empleado no encontrado",
  detalle: "No existe ningún empleado con nifnie " ++ ((vars.empleadoEntrada.nifnie default "desconocido") as String),
  codigo: "APP:EMPLEADO_NO_ENCONTRADO"
}]

#[{
  mensaje: "El proceso se ha tenido que cancelar por errores durante la ejecución",
  detalle: (error.errorType.namespace default "APP") ++ ":" ++ (error.errorType.identifier default "UNKNOWN"),
  codigo: (error.errorType.namespace default "APP") ++ ":" ++ (error.errorType.identifier default "UNKNOWN")
}]

