ee:message.ee:set-payload:
%dw 2.0
output application/java
ns ns0 http://www.example.org/Empleados/
var e = vars.empleadoRows[0]
---
{
    body: {
        ns0#consultarEmpleadoResponse: {
            out: {
                nifnie: e.nifnie,
                nombreApellidos: e.nombreApellidos,
                email: e.email,
                naf: e.naf,
                iban: e.iban,
                idNivel: e.idNivel as Number,
                usuario: e.usuario,
                password: e.password,
                valido: ((e.valido default 0) as Number) == 1
            },
            error: ""
        }
    } write "application/xml"
}

set-variable.value:
#[{
  mensaje: "WSKey inválida o no proporcionada",
  detalle: "La WSKey recibida no existe en la tabla soapkey",
  codigo: "APP:WSKEY_INVALIDA"
}]

#[{
  mensaje: "NIFNIE no encontrado o erróneo",
  detalle: "No existe ningún empleado con nifnie " ++ ((vars.nifnie default "desconocido") as String),
  codigo: "APP:EMPLEADO_NO_ENCONTRADO"
}]

#[{
  mensaje: "El proceso se ha tenido que cancelar por errores durante la ejecución",
  detalle: (error.errorType.namespace default "APP") ++ ":" ++ (error.errorType.identifier default "UNKNOWN"),
  codigo: (error.errorType.namespace default "APP") ++ ":" ++ (error.errorType.identifier default "UNKNOWN")
}]

ee:message.ee:set-payload:
%dw 2.0
output application/java
ns ns0 http://www.example.org/Empleados/
---
{
    body: {
        ns0#consultarTodosEmpleadosResponse: {
            out: vars.empleadosRows map (e) -> {
                nifnie: e.nifnie,
                nombreApellidos: e.nombreApellidos,
                email: e.email,
                naf: e.naf,
                iban: e.iban,
                idNivel: e.idNivel as Number,
                usuario: e.usuario,
                password: e.password,
                valido: ((e.valido default 0) as Number) == 1
            },
            error: ""
        }
    } write "application/xml"
}

set-variable.value:
#[{
  mensaje: "WSKey inválida o no proporcionada",
  detalle: "La WSKey recibida no existe en la tabla soapkey",
  codigo: "APP:WSKEY_INVALIDA"
}]

#[{
